function scrollToTop(){window.scrollTo({top:0,behavior:'smooth'});}document.addEventListener('DOMContentLoaded',function(){const links=document.querySelectorAll('a[href^="#"]');links.forEach(link=>{link.addEventListener('click',function(e){e.preventDefault();const targetId=this.getAttribute('href');const targetElement=document.querySelector(targetId);if(targetElement){targetElement.scrollIntoView({behavior:'smooth'});}});});const stickyDownload=document.querySelector('.sticky-download');if(stickyDownload){window.addEventListener('scroll',function(){if(window.scrollY>100){stickyDownload.style.display='flex';}});}});function highlightTOC(){const tocLinks=document.querySelectorAll('.table-of-contents a');const sections=document.querySelectorAll('.article-content h2,.article-content h3');window.addEventListener('scroll',function(){let current='';sections.forEach(section=>{const sectionTop=section.offsetTop;if(window.scrollY>=sectionTop-100){current=section.getAttribute('id');}});tocLinks.forEach(link=>{link.classList.remove('active');if(link.getAttribute('href')==='#'+current){link.classList.add('active');}});});}const categoryConfig={'category1':{icon:'🗑️',name:'自动删消息设置'},'category2':{icon:'🧹',name:'私聊记录清理'},'category3':{icon:'👥',name:'群组消息管理'},'category4':{icon:'⏰',name:'定时清理规则'},'category5':{icon:'💾',name:'聊天记录维护'}};function renderArticles(articles){const container=document.getElementById('articles-container');if(!container)return;const grouped={};articles.forEach(function(article){var cat=article.categoryId;if(!grouped[cat])grouped[cat]=[];grouped[cat].push(article);});var html='';['category1','category2','category3','category4','category5'].forEach(function(catId){var cfg=categoryConfig[catId];var catArticles=grouped[catId]||[];html+='<h3 class="cat-heading">'+cfg.icon+' '+cfg.name+'</h3>';html+='<div class="article-grid">';catArticles.forEach(function(a){html+='<a href="/article'+a.id+'.html" class="article-card">';html+='<img class="article-image" src="'+a.cover+'" alt="Telegram教程" loading="lazy">';html+='<div class="article-content"><h3>'+a.title+'</h3>';html+='<p class="article-meta">分类：'+cfg.name+'</p></div></a>';});html+='</div>';});container.innerHTML=html;}function loadArticles(){var xhr=new XMLHttpRequest();xhr.onreadystatechange=function(){if(xhr.readyState===4&&xhr.status===200){try{var articles=JSON.parse(xhr.responseText);renderArticles(articles);}catch(e){document.getElementById('articles-container').innerHTML='<p style="text-align:center;color:#999;">教程列表加载失败，请刷新页面重试。</p>';}}};xhr.open('GET','data/articles.json',true);xhr.send();}if(document.querySelector('#articles-container')){loadArticles();}if(document.querySelector('.article-container')){highlightTOC();}
